      customer: { yearsWithMHPCO: 5 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 65 }] });
  });
  it.todo("quote for a single plain staff yields 85 G (80 base + 5 fee)");
  it.todo("quote for a single plain potion yields 45 G (40 base + 5 fee)");

  // Components
  it.todo("quote for a single rune yields 30 G (25 base + 5 fee)");
  it.todo("quote for 2 runes yields 55 G (50 base + 5 fee)");
  it.todo("quote for 3 runes yields 65 G (block: 60 base + 5 fee)");
  it.todo("quote for 4 runes yields 105 G (100 base + 5 fee, no block)");
  it.todo("quote for 7 runes yields 180 G (175 base + 5 fee)");

  // Alike components
  it.todo("quote for 2 runes + 1 moonstone yields 80 G (75 base + 5 fee, no block)");
  it.todo("quote for 3 runes + 3 moonstones yields 125 G (120 base + 5 fee, two blocks)");

  // Item-specific modifiers
  it.todo("cursed sword adds 50% surcharge on item base premium");
  it.todo("sword with enchantment 5 adds 30% high-enchantment surcharge");
  it.todo("sword with enchantment 4 has no high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5 gets both surcharges");

  // Modifier scope on multi-item policy
  it.todo("policy with cursed sword + plain amulet: curse surcharge applies only to sword");

  // Customer modifiers
  it.todo("customer with exactly 2 years gets 20% loyalty discount");
  it.todo("first insurance adds 10% surcharge per item");
  it.todo("follow-up contract gets 15% discount on policy");

  // Rounding
  it.todo("premium that yields 197.5 G rounds UP to 198 G");
  it.todo("payout that yields 350.5 G rounds DOWN to 350 G");

  // Integration examples
  it.todo("newcomer with cursed sword (steel, enchantment 3) → premium 165 G");
  it.todo("3-year customer's second quote with cursed sword (steel, enchantment 7) → premium 160 G");

  // Claim: standard reimbursement
  it.todo("regular sword damage 500 G → payout 400 G (deductible)");
  it.todo("rune damage 200 G → payout 100 G (deductible)");

  // Claim: special clauses
  it.todo("dragon-material sword enchantment 8 damage 1000 G → payout 400 G (50% then deductible)");
  it.todo("dragon-material sword enchantment 9 damage 1000 G → payout 400 G (50% wins)");
  it.todo("dragon-material sword enchantment 5 damage 800 G → payout 700 G (full then deductible)");
  it.todo("steel sword enchantment 9 damage 1000 G → payout 400 G (50% then deductible)");

