const PROCESSING_FEE = 5;
const BLOCK_PRICE = 60;

const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

type Item = { type: string };
type Step = { items: Item[] };
type Scenario = { steps: Step[] };

const basePremiumFor = (item: Item): number =>
  BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;

const isBlockOfThreeRunes = (items: Item[]): boolean =>
  items.length === 3 && items.every((item) => item.type === "rune");

const sumBasePremiums = (items: Item[]): number => {
  if (isBlockOfThreeRunes(items)) return BLOCK_PRICE;
  return items.reduce((sum, item) => sum + basePremiumFor(item), 0);
};

const quotePremiumFor = (step: Step): number =>
  sumBasePremiums(step.items) + PROCESSING_FEE;

export const processScenario = (input: unknown): unknown => {
  const { steps } = input as Scenario;
  return { results: steps.map((step) => ({ premium: quotePremiumFor(step) })) };
};

