const isBlockOfAlikeComponents = (type: string, count: number): boolean =>
  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;

const priceForGroup = (type: string, count: number): number =>
  isBlockOfAlikeComponents(type, count)
    ? BLOCK_PRICE
    : count * basePremiumFor(type);

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const CURSE_SURCHARGE_RATE = 0.5;

const itemSurcharge = (item: Item): number =>
  item.cursed ? basePremiumFor(item.type) * CURSE_SURCHARGE_RATE : 0;

const sumGroupedPrices = (items: Item[]): number => {
  let total = 0;
  for (const [type, count] of countByType(items)) {
    total += priceForGroup(type, count);
  }
  return total;
};

const sumItemSurcharges = (items: Item[]): number => {
  let total = 0;
  for (const item of items) {
    total += itemSurcharge(item);
  }
  return total;
};

const sumItemPrices = (items: Item[]): number =>
  sumGroupedPrices(items) + sumItemSurcharges(items);

const quotePremiumFor = (step: Step): number =>
  sumItemPrices(step.items) + PROCESSING_FEE;

export const processScenario = (input: unknown): unknown => {
  const { steps } = input as Scenario;
  return { results: steps.map((step) => ({ premium: quotePremiumFor(step) })) };
};

